// does not recurse.
private void normalise(Element element) {
    List<Node> prepend = new ArrayList<Node>();
    List<Node> append = new ArrayList<Node>();

    // find the split point for this element (the point where the body starts)
    Element split = null;
    if (element == this) {
        split = select("html").first();
    } else if (element.tagName().equals("html")) {
        split = body();
    }

    boolean seenSplit = false;
    for (Node node: element.childNodes) {
        if (node == split) {
            seenSplit = true;
        }
        if (node instanceof TextNode) {
            TextNode tn = (TextNode) node;
            if (!tn.isBlank()) {
                if (seenSplit)
                    append.add(tn);
                else
                    prepend.add(tn);
            }
        }
    }

    for (int i = prepend.size() - 1; i >= 0; i--) {
        Node node = prepend.get(i);
        element.removeChild(node);
        body().prependChild(new TextNode(" ", ""));
        body().prependChild(node);
    }

    for (Node node: append) {
        element.removeChild(node);
        body().appendChild(new TextNode(" ", ""));
        body().appendChild(node);
    }
}

